/**
 * Audit logging service — records every notification dispatched through the system.
 *
 * Plugs into the PriorityRouter to capture a log entry for each routed notification,
 * including channel, priority, recipient, and timestamp.
 */

import type { NotificationPriority, PriorityNotification } from './priority-router.js';

export interface AuditEntry {
  id: string;
  channel: string;
  priority: NotificationPriority;
  recipient: string;
  subject: string;
  timestamp: Date;
}

let nextId = 1;

function generateAuditId(): string {
  return `audit-${String(nextId++).padStart(4, '0')}`;
}

export function resetAuditIdCounter(): void {
  nextId = 1;
}

export class AuditService {
  private entries: AuditEntry[] = [];

  /**
   * Record a notification dispatch.
   */
  record(channel: string, notification: PriorityNotification): void {
    const entry: AuditEntry = {
      id: generateAuditId(),
      channel,
      priority: notification.priority,
      recipient: notification.recipient,
      subject: notification.subject,
      timestamp: new Date(),
    };
    this.entries.push(entry);
  }

  getEntries(): AuditEntry[] {
    return [...this.entries];
  }

  getEntriesByChannel(channel: string): AuditEntry[] {
    return this.entries.filter((e) => e.channel === channel);
  }

  getEntriesByRecipient(recipient: string): AuditEntry[] {
    return this.entries.filter((e) => e.recipient === recipient);
  }

  getEntryCount(): number {
    return this.entries.length;
  }

  clear(): void {
    this.entries = [];
  }
}

/**
 * Notification preferences service — allows per-user channel preferences
 * that override the default priority-based routing.
 *
 * If a user has set a preferred channel, that channel is used regardless
 * of the notification's priority level. If no preference is set, the
 * PriorityRouter's default mapping applies.
 */

export type ChannelPreference = 'sms' | 'email' | 'webhook';

export class NotificationPreferencesService {
  private preferences: Map<string, ChannelPreference> = new Map();

  /**
   * Set a user's preferred notification channel.
   */
  setPreference(userId: string, channel: ChannelPreference): void {
    this.preferences.set(userId, channel);
  }

  /**
   * Remove a user's channel preference (fall back to priority routing).
   */
  removePreference(userId: string): void {
    this.preferences.delete(userId);
  }

  /**
   * Get a user's preferred channel, or undefined if not set.
   */
  getPreference(userId: string): ChannelPreference | undefined {
    return this.preferences.get(userId);
  }

  /**
   * Check whether a user has a channel preference set.
   */
  hasPreference(userId: string): boolean {
    return this.preferences.has(userId);
  }

  clear(): void {
    this.preferences.clear();
  }
}

