import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent, AppEvent } from '../events/event-types.js';
import type { NotificationService } from './notification.service.js';
import type { SmsChannelService } from './sms-channel.service.js';
import type { WebhookChannelService } from './webhook-channel.service.js';
import type { AuditService } from './audit.service.js';
import type { NotificationPreferencesService, ChannelPreference } from './notification-preferences.service.js';
import { Logger } from '../utils/logger.js';

export type NotificationPriority = 'urgent' | 'normal' | 'low';

export interface PriorityNotification {
  priority: NotificationPriority;
  recipient: string;
  subject: string;
  body: string;
  event: AppEvent;
}

export class PriorityRouter {
  private logger = new Logger('PriorityRouter');
  private routingLog: Array<{ priority: NotificationPriority; channel: string; notification: PriorityNotification }> = [];
  private auditService: AuditService | null = null;
  private preferencesService: NotificationPreferencesService | null = null;

  constructor(
    private smsChannel: SmsChannelService,
    private emailChannel: NotificationService,
    private webhookChannel: WebhookChannelService,
  ) {}

  /**
   * Attach an audit service to log all dispatched notifications.
   */
  setAuditService(audit: AuditService): void {
    this.auditService = audit;
  }

  /**
   * Attach a preferences service to allow per-user channel overrides.
   */
  setPreferencesService(preferences: NotificationPreferencesService): void {
    this.preferencesService = preferences;
  }

  /**
   * Route a notification to the appropriate channel based on priority,
   * or to the user's preferred channel if one is set.
   */
  route(notification: PriorityNotification): void {
    const channel = this.resolveChannel(notification);
    this.logger.info(`Routing ${notification.priority} notification to ${channel}`);

    this.dispatchToChannel(channel, notification);
    this.routingLog.push({ priority: notification.priority, channel, notification });

    if (this.auditService) {
      this.auditService.record(channel, notification);
    }
  }

  private resolveChannel(notification: PriorityNotification): string {
    if (this.preferencesService?.hasPreference(notification.recipient)) {
      return this.preferencesService.getPreference(notification.recipient)!;
    }
    return this.channelName(notification.priority);
  }

  private dispatchToChannel(channel: string, notification: PriorityNotification): void {
    switch (channel) {
      case 'sms':
        this.smsChannel.send({
          to: notification.recipient,
          body: `[URGENT] ${notification.subject}: ${notification.body}`,
        });
        break;

      case 'email':
        this.emailChannel.send({
          recipient: notification.recipient,
          subject: notification.subject,
          body: notification.body,
        });
        break;

      case 'webhook':
        this.webhookChannel.deliver(notification.event);
        break;
    }
  }

