import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { PriorityRouter } from '../../src/services/priority-router.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import {
  SmsChannelService,
  resetSmsIdCounter,
} from '../../src/services/sms-channel.service.js';
import {
  WebhookChannelService,
  resetWebhookIdCounter,
} from '../../src/services/webhook-channel.service.js';
import { AuditService, resetAuditIdCounter } from '../../src/services/audit.service.js';
import { NotificationPreferencesService } from '../../src/services/notification-preferences.service.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('Notification flow integration', () => {
  let eventBus: EventBus;
  let smsChannel: SmsChannelService;
  let emailChannel: NotificationService;
  let webhookChannel: WebhookChannelService;
  let router: PriorityRouter;
  let audit: AuditService;
  let preferences: NotificationPreferencesService;

  const orderCreatedEvent: OrderCreatedEvent = {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [
        { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
      ],
      total: 20,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
  };

  const statusChangedEvent: OrderStatusChangedEvent = {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 20,
      status: 'confirmed',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date(),
  };

  beforeEach(() => {
    eventBus = new EventBus();
    statusChangeCallbacks.clear();
    smsChannel = new SmsChannelService(eventBus);
    emailChannel = new NotificationService(eventBus);
    webhookChannel = new WebhookChannelService(eventBus);
    audit = new AuditService();
    preferences = new NotificationPreferencesService();
    router = new PriorityRouter(smsChannel, emailChannel, webhookChannel);
    router.setAuditService(audit);
    router.setPreferencesService(preferences);
    emailChannel.setPriorityRouter(router);
    resetSmsIdCounter();
    resetNotificationIdCounter();
    resetWebhookIdCounter();
    resetAuditIdCounter();
  });

  describe('priority routing → channel selection → audit log', () => {
    it('urgent notification routes to SMS and creates audit entry', () => {
      router.route({
        priority: 'urgent',
        recipient: 'user-1',
        subject: 'Order Issue',
        body: 'Your order needs attention.',
        event: statusChangedEvent,
      });

      expect(smsChannel.getMessageCount()).toBe(1);
      expect(emailChannel.getNotificationCount()).toBe(0);
      expect(webhookChannel.getDeliveryCount()).toBe(0);

      const entries = audit.getEntries();
      expect(entries).toHaveLength(1);
      expect(entries[0]?.channel).toBe('sms');
      expect(entries[0]?.priority).toBe('urgent');
      expect(entries[0]?.recipient).toBe('user-1');
    });

    it('normal notification routes to email and creates audit entry', () => {
      router.route({
        priority: 'normal',
        recipient: 'alice@example.com',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        event: orderCreatedEvent,
      });

      expect(emailChannel.getNotificationCount()).toBe(1);
      expect(smsChannel.getMessageCount()).toBe(0);

      const entries = audit.getEntries();
      expect(entries).toHaveLength(1);
      expect(entries[0]?.channel).toBe('email');
      expect(entries[0]?.priority).toBe('normal');
    });

    it('low notification routes to webhook and creates audit entry', () => {
      webhookChannel.registerWebhookUrl('order:created', 'https://hooks.example.com/orders');

      router.route({
        priority: 'low',
        recipient: 'user-1',
        subject: 'Minor Update',
        body: 'Something changed.',
        event: orderCreatedEvent,
      });

      expect(webhookChannel.getDeliveryCount()).toBe(1);
      expect(smsChannel.getMessageCount()).toBe(0);
      expect(emailChannel.getNotificationCount()).toBe(0);

      const entries = audit.getEntries();
      expect(entries).toHaveLength(1);
      expect(entries[0]?.channel).toBe('webhook');
      expect(entries[0]?.priority).toBe('low');
    });

    it('multiple notifications produce sequential audit entries', () => {
      webhookChannel.registerWebhookUrl('order:created', 'https://hooks.example.com/orders');

      router.route({
        priority: 'urgent',
        recipient: 'user-1',
        subject: 'Urgent',
        body: 'Urgent message.',
        event: statusChangedEvent,
      });
      router.route({
        priority: 'normal',
        recipient: 'alice@example.com',
        subject: 'Normal',
        body: 'Normal message.',
        event: orderCreatedEvent,
      });
      router.route({
        priority: 'low',
        recipient: 'user-1',
        subject: 'Low',
        body: 'Low message.',
        event: orderCreatedEvent,
      });

      const entries = audit.getEntries();
      expect(entries).toHaveLength(3);
      expect(entries[0]?.id).toBe('audit-0001');
      expect(entries[1]?.id).toBe('audit-0002');
      expect(entries[2]?.id).toBe('audit-0003');
      expect(entries.map((e) => e.channel)).toEqual(['sms', 'email', 'webhook']);
    });
  });

  describe('user preferences override priority routing', () => {
    it('user with SMS preference receives SMS even for normal-priority notification', () => {
      preferences.setPreference('alice@example.com', 'sms');

      router.route({
        priority: 'normal',
        recipient: 'alice@example.com',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        event: orderCreatedEvent,
      });

      expect(smsChannel.getMessageCount()).toBe(1);
      expect(emailChannel.getNotificationCount()).toBe(0);

      const entries = audit.getEntries();
      expect(entries).toHaveLength(1);
      expect(entries[0]?.channel).toBe('sms');
    });

    it('user with email preference receives email even for urgent notification', () => {
      preferences.setPreference('user-1', 'email');

      router.route({
        priority: 'urgent',
        recipient: 'user-1',
        subject: 'Urgent Order',
        body: 'Needs attention.',
        event: statusChangedEvent,
      });

      expect(emailChannel.getNotificationCount()).toBe(1);
      expect(smsChannel.getMessageCount()).toBe(0);

      const entries = audit.getEntries();
      expect(entries[0]?.channel).toBe('email');
    });

    it('user with webhook preference receives webhook even for urgent notification', () => {
      webhookChannel.registerWebhookUrl('order:status-changed', 'https://hooks.example.com/status');
      preferences.setPreference('user-1', 'webhook');

      router.route({
        priority: 'urgent',
        recipient: 'user-1',
        subject: 'Urgent Order',
        body: 'Needs attention.',
        event: statusChangedEvent,
      });

      expect(webhookChannel.getDeliveryCount()).toBe(1);
      expect(smsChannel.getMessageCount()).toBe(0);
      expect(emailChannel.getNotificationCount()).toBe(0);

      const entries = audit.getEntries();
      expect(entries[0]?.channel).toBe('webhook');
    });

    it('removing preference restores priority-based routing', () => {
      preferences.setPreference('user-1', 'email');

      router.route({
        priority: 'urgent',
        recipient: 'user-1',
        subject: 'First',
        body: 'Goes to email.',
        event: statusChangedEvent,
      });
      expect(emailChannel.getNotificationCount()).toBe(1);

      preferences.removePreference('user-1');

      router.route({
        priority: 'urgent',
        recipient: 'user-1',
        subject: 'Second',
        body: 'Goes to SMS.',
        event: statusChangedEvent,
      });
      expect(smsChannel.getMessageCount()).toBe(1);

      const entries = audit.getEntries();
      expect(entries).toHaveLength(2);
      expect(entries[0]?.channel).toBe('email');
      expect(entries[1]?.channel).toBe('sms');
    });

    it('users without preferences use default priority routing', () => {
      preferences.setPreference('other-user', 'webhook');

      router.route({
        priority: 'urgent',
        recipient: 'user-1',
        subject: 'Urgent',
        body: 'Default routing.',
        event: statusChangedEvent,
      });

      expect(smsChannel.getMessageCount()).toBe(1);
      expect(audit.getEntries()[0]?.channel).toBe('sms');
    });
  });

  describe('end-to-end via sendWithPriority', () => {
    it('sendWithPriority flows through router, preferences, and audit', () => {
      preferences.setPreference('alice@example.com', 'sms');

      emailChannel.sendWithPriority({
        priority: 'normal',
        recipient: 'alice@example.com',
        subject: 'Order Confirmation',
        body: 'Your order is confirmed.',
        event: orderCreatedEvent,
      });

      // Preference overrides: goes to SMS instead of email
      expect(smsChannel.getMessageCount()).toBe(1);
      expect(emailChannel.getNotificationCount()).toBe(0);

      const entries = audit.getEntries();
      expect(entries).toHaveLength(1);
      expect(entries[0]?.channel).toBe('sms');
      expect(entries[0]?.subject).toBe('Order Confirmation');
    });
  });

  describe('audit service queries', () => {
    it('filters entries by channel', () => {
      router.route({ priority: 'urgent', recipient: 'u1', subject: 'A', body: 'A', event: statusChangedEvent });
      router.route({ priority: 'normal', recipient: 'u2', subject: 'B', body: 'B', event: orderCreatedEvent });
      router.route({ priority: 'urgent', recipient: 'u3', subject: 'C', body: 'C', event: statusChangedEvent });

      expect(audit.getEntriesByChannel('sms')).toHaveLength(2);
      expect(audit.getEntriesByChannel('email')).toHaveLength(1);
      expect(audit.getEntriesByChannel('webhook')).toHaveLength(0);
    });

    it('filters entries by recipient', () => {
      router.route({ priority: 'urgent', recipient: 'user-1', subject: 'A', body: 'A', event: statusChangedEvent });
      router.route({ priority: 'normal', recipient: 'user-1', subject: 'B', body: 'B', event: orderCreatedEvent });
      router.route({ priority: 'urgent', recipient: 'user-2', subject: 'C', body: 'C', event: statusChangedEvent });

      expect(audit.getEntriesByRecipient('user-1')).toHaveLength(2);
      expect(audit.getEntriesByRecipient('user-2')).toHaveLength(1);
    });
  });
});

