+        recipient: 'user-1',
+        subject: 'Minor Update',
+        body: 'Something changed.',
+        event: orderCreatedEvent,
+      });
+
+      expect(webhookChannel.getDeliveryCount()).toBe(1);
+      expect(smsChannel.getMessageCount()).toBe(0);
+      expect(emailChannel.getNotificationCount()).toBe(0);
+
+      const entries = audit.getEntries();
+      expect(entries).toHaveLength(1);
+      expect(entries[0]?.channel).toBe('webhook');
+      expect(entries[0]?.priority).toBe('low');
+    });
+
+    it('multiple notifications produce sequential audit entries', () => {
+      webhookChannel.registerWebhookUrl('order:created', 'https://hooks.example.com/orders');
